    public void test_TC06() {
        // GIVEN a new Document and default OutputSettings
        Document doc = new Document("http://example.com");
        OutputSettings settings = new OutputSettings();

        // WHEN applying xml syntax: this branch in OutputSettings.syntax should set escapeMode to xhtml
